import "./main.css";
import EqualizerEditor from "../equalizer/equalizer";

// ── 상수들 ──
const sampleRate = 44100;
const numPoints = 200;
const initialEQChannels = [
  { name: "Low-cut", freq: 80, Q: 0.7, gain: 0, enabled: true, eqMode: "PEQ", color: "#1abc9c" },
  { name: "Low",     freq: 120, Q: 1.0, gain: 0, eqMode: "PEQ", color: "#3498db" },
  { name: "Low-mid", freq: 400, Q: 1.0, gain: 0, eqMode: "PEQ", color: "#9b59b6" },
  { name: "Mid",     freq: 1000, Q: 1.0, gain: 0, eqMode: "PEQ", color: "#e67e22" },
  { name: "High-mid",freq: 4000, Q: 1.0, gain: 0, eqMode: "PEQ", color: "#e74c3c" },
  { name: "High",    freq: 8000, Q: 1.0, gain: 0, eqMode: "PEQ", color: "#f1c40f" },
  { name: "Presence",freq: 10000, Q: 1.0, gain: 0, eqMode: "PEQ", color: "#2ecc71" },
  { name: "High-cut",freq: 12000, Q: 0.7, gain: 0, enabled: true, eqMode: "PEQ", color: "#95a5a6" }
];
