// ── 헬퍼 함수들 ──

const loadAudioBuffer = async (url, audioContext) => {
  const response = await fetch(url);
  const arrayBuffer = await response.arrayBuffer();
  return await audioContext.decodeAudioData(arrayBuffer);
};

const bufferToWave = (abuffer, len) => {
  const numOfChan = abuffer.numberOfChannels,
    length = len * numOfChan * 2 + 44,
    buffer = new ArrayBuffer(length),
    view = new DataView(buffer),
    sr = abuffer.sampleRate;
  let pos = 0;
  const setUint16 = (data) => { view.setUint16(pos, data, true); pos += 2; };
  const setUint32 = (data) => { view.setUint32(pos, data, true); pos += 4; };
  for (let i = 0; i < 4; i++) { view.setUint8(pos++, "RIFF".charCodeAt(i)); }
  setUint32(length - 8);
  for (let i = 0; i < 4; i++) { view.setUint8(pos++, "WAVE".charCodeAt(i)); }
  for (let i = 0; i < 4; i++) { view.setUint8(pos++, "fmt ".charCodeAt(i)); }
  setUint32(16);
  setUint16(1);
  setUint16(numOfChan);
  setUint32(sr);
  setUint32(sr * numOfChan * 2);
  setUint16(numOfChan * 2);
  setUint16(16);
  for (let i = 0; i < 4; i++) { view.setUint8(pos++, "data".charCodeAt(i)); }
  setUint32(length - pos);
  const channels = [];
  for (let i = 0; i < numOfChan; i++) { channels.push(abuffer.getChannelData(i)); }
  for (let i = 0; i < len; i++) {
    for (let channel = 0; channel < numOfChan; channel++) {
      let sample = channels[channel][i] || 0;
      sample = Math.max(-1, Math.min(1, sample));
      view.setInt16(pos, sample < 0 ? sample * 0x8000 : sample * 0x7FFF, true);
      pos += 2;
    }
  }
  return new Blob([buffer], { type: "audio/wav" });
};

const extractWaveform = (audioData) => {
  const samples = 1000;
  const blockSize = Math.floor(audioData.length / samples) || 1;
  const waveform = [];
  for (let i = 0; i < samples; i++) {
    let blockMin = 1;
    let blockMax = -1;
    for (let j = 0; j < blockSize; j++) {
      let sample = audioData[i * blockSize + j];
      if (sample > 0.8) sample = 0.8;
      if (sample < -0.8) sample = -0.8;
      if (sample < blockMin) blockMin = sample;
      if (sample > blockMax) blockMax = sample;
    }
    const min_dB = blockMin * 15;
    const max_dB = blockMax * 15;
    const normalizedMin = (min_dB + 15) / 30;
    const normalizedMax = (max_dB + 15) / 30;
    waveform.push({ min: normalizedMin, max: normalizedMax });
  }
  return waveform;
};

// ── ChannelVisualizer 컴포넌트 ──
// 파형, 스펙트럼, 주파수 막대 그래프를 그리며, 타임라인 슬라이더로 재생 위치 제어
const ChannelVisualizer = ({ analyser, staticWaveform, isPlaying, audioElement, duration, isRecording }) => {
  const waveformRef = useRef(null);
  const spectrumRef = useRef(null);
  const frequencyRef = useRef(null);
  const [currentTime, setCurrentTime] = useState(0);
  const frameCounter = useRef(0);
  const xMarkers = [20, 40, 60, 100, 200, 400, 600, 1000, 2000, 3000, 4000, 5000, 6000, 10000, 20000];

  // 캔버스 크기 업데이트 함수
  const updateCanvasSize = (canvas) => {
    if (canvas) {
      canvas.width = canvas.clientWidth;
      canvas.height = canvas.clientHeight;
    }
  };

  useEffect(() => {
    let timer;
    if (audioElement) {
      timer = setInterval(() => setCurrentTime(audioElement.currentTime), 100);
    }
    return () => { if (timer) clearInterval(timer); };
  }, [audioElement]);

  // 오디오 파형 그리기
  useEffect(() => {
    const canvas = waveformRef.current;
    if (!canvas) return;
    updateCanvasSize(canvas);
    const ctx = canvas.getContext("2d");
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.fillStyle = "#111";
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    if (isRecording && analyser) {
      const bufferLength = analyser.fftSize;
      const dataArray = new Uint8Array(bufferLength);
      analyser.getByteTimeDomainData(dataArray);
      ctx.strokeStyle = "#A6826D";
      ctx.lineWidth = 2;
      ctx.beginPath();
      const sliceWidth = canvas.width / bufferLength;
      let x = 0;
      for (let i = 0; i < bufferLength; i++) {
        const v = dataArray[i] / 128.0;
        const y = (v * canvas.height) / 2;
        if (i === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
        x += sliceWidth;
      }
      ctx.stroke();
    } else if (staticWaveform && staticWaveform.length > 0) {
      const sliceWidth = canvas.width / staticWaveform.length;
      const markerX = duration ? (currentTime / duration) * canvas.width : 0;
      for (let i = 0; i < staticWaveform.length; i++) {
        const block = staticWaveform[i];
        const x = i * sliceWidth;
        const yTop = canvas.height - (block.max * canvas.height);
        const yBottom = canvas.height - (block.min * canvas.height);
        ctx.beginPath();
        ctx.strokeStyle = (x < markerX) ? "#A6826D" : "#BFBFBF";
        ctx.moveTo(x, yTop);
        ctx.lineTo(x, yBottom);
        ctx.stroke();
      }
      ctx.beginPath();
      ctx.strokeStyle = "#735449";
      ctx.lineWidth = 2;
      ctx.moveTo(markerX, 0);
      ctx.lineTo(markerX, canvas.height);
      ctx.stroke();
    }
  }, [staticWaveform, currentTime, duration, isRecording, analyser]);

  // 스펙트럼(스펙트로그램) 그리기 – 시간에 따라 스크롤되는 방식
  useEffect(() => {
    if (!analyser) return;
    const canvas = spectrumRef.current;
    if (!canvas) return;
    updateCanvasSize(canvas);
    const ctx = canvas.getContext("2d");
    const bufferLength = analyser.frequencyBinCount;
    const freqData = new Uint8Array(bufferLength);
    let lastTime = performance.now();
    const drawSpectrum = (now) => {
      const deltaTime = now - lastTime;
      lastTime = now;
      // 스펙트럼이 5초간 기록되도록: canvas.height corresponds to 5s
      const shiftPixels = (deltaTime / 5000) * canvas.height;
      // 스크롤 효과: 기존 내용을 위로 shift
      ctx.drawImage(canvas, 0, -shiftPixels, canvas.width, canvas.height);
      // 새로 그릴 영역 (하단)
      ctx.fillStyle = "#111";
      ctx.fillRect(0, canvas.height - shiftPixels, canvas.width, shiftPixels);
      // 최신 스펙트럼 데이터 행 그리기
      analyser.getByteFrequencyData(freqData);
      for (let x = 0; x < canvas.width; x++) {
        const bin = Math.floor((x / canvas.width) * bufferLength);
        const value = freqData[bin];
        // 0~255 값을 흰색 계열로 매핑 (값이 높을수록 밝게)
        ctx.fillStyle = `rgb(${value}, ${value}, ${value})`;
        ctx.fillRect(x, canvas.height - shiftPixels, 1, shiftPixels);
      }
      requestAnimationFrame(drawSpectrum);
    };
    requestAnimationFrame(drawSpectrum);
  }, [analyser, isPlaying]);

  // 주파수 막대 그래프 그리기 (Y축: 0 dB ~ +15 dB)
  useEffect(() => {
    const canvas = frequencyRef.current;
    if (!canvas) return;
    updateCanvasSize(canvas);
    const ctx = canvas.getContext("2d");
    const width = canvas.width;
    const height = canvas.height;
    ctx.clearRect(0, 0, width, height);
    ctx.fillStyle = "#111";
    ctx.fillRect(0, 0, width, height);
    xMarkers.forEach(f => {
      const xPos = Math.log(f / 20) / Math.log(20000 / 20) * width;
      ctx.fillStyle = "#BFBFBF";
      ctx.font = "10px Arial";
      ctx.textAlign = "center";
      ctx.fillText(f, xPos, height - 2);
      ctx.beginPath();
      ctx.moveTo(xPos, height);
      ctx.lineTo(xPos, height - 5);
      ctx.strokeStyle = "#BFBFBF";
      ctx.stroke();
    });
    // Y축 표시: 바 그래프는 0dB에서 시작하여 +15dB까지
    ctx.textAlign = "right";
    ctx.fillText("0 dB", 30, height - 2);
    ctx.fillText("+15 dB", 30, 15);
    ctx.beginPath();
    ctx.moveTo(0, height - 2);
    ctx.lineTo(width, height - 2);
    ctx.strokeStyle = "#735449";
    ctx.lineWidth = 2;
    ctx.stroke();
    // 주파수 데이터 막대 그리기
    // (실제 주파수 데이터를 그리기 위해 analyser에서 읽은 데이터가 필요하지만,
    //  여기서는 예시로 임의의 데이터를 사용하여 전체 캔버스를 채우도록 함)
    // 만약 주파수 데이터가 있다면, 아래 코드를 analyser.getByteFrequencyData()로 대체하세요.
    // 예) let freqData = new Uint8Array(analyser.frequencyBinCount); analyser.getByteFrequencyData(freqData);
    // 여기서는 단순히 0~255의 임의 값으로 채운다고 가정합니다.
    const dummyFreqData = new Uint8Array(width).map(() => Math.floor(Math.random() * 256));
    for (let x = 0; x < width; x++) {
      // 매 x 위치의 값 (0~255) -> 막대 높이 계산
      const value = dummyFreqData[x];
      const barHeight = (value / 255) * height;
      ctx.fillStyle = "#BFBFBF";
      ctx.fillRect(x, height - barHeight, 1, barHeight);
    }
  }, []);

  return (
    <div className="main-visualizer-container" style={{ display: "flex", flexDirection: "row", height: "300px" }}>
      <canvas className="main-waveform" ref={waveformRef} style={{ border: "1px solid #444", marginRight: "5px", width: "600px", height: "200px" }} />
      <div className="main-spectrogram-container" style={{ display: "flex", flexDirection: "column", flex: 1 }}>
        <canvas className="main-spectrum" ref={spectrumRef} style={{ border: "1px solid #444", marginBottom: "2px", width: "100%", height: "150px" }} />
        <div className="main-frequency-container" style={{ flex: 1 }}>
          <div className="main-hz-axis" style={{ display: "flex", justifyContent: "space-between" }}>
            {xMarkers.map((f, i) => (
              <div key={i} className="main-hz-label" style={{ fontSize: "10px", color: "#BFBFBF" }}>{f} Hz</div>
            ))}
          </div>
          <canvas className="main-frequency" ref={frequencyRef} style={{ border: "1px solid #444", marginTop: "2px", cursor: "pointer", width: "100%", height: "150px" }} onClick={() => {}} />
        </div>
      </div>
    </div>
  );
};

// ── Main 컴포넌트 ──
const Main = () => {
  const [channels, setChannels] = useState(() => {
    const saved = localStorage.getItem("channels");
    if (saved) return JSON.parse(saved);
    return [{
      id: 1,
      name: "Channel 1",
      volume: 50,
      pan: 0,
      isMuted: false,
      isSolo: false,
      inputSource: "microphone",
      waveform: [],
      duration: 0,
      isRecording: false,
      mediaRecorder: null,
      audioUrl: null,
      isPlaying: false,
      isSelected: false,
      playbackOffset: 0,
      eq: JSON.parse(JSON.stringify(initialEQChannels))
    }];
  });
  useEffect(() => {
    const persist = channels.map(({ id, name, volume, pan, isMuted, isSolo, inputSource, waveform, duration, audioUrl, isPlaying, isSelected, eq, playbackOffset }) => ({
      id, name, volume, pan, isMuted, isSolo, inputSource, waveform, duration, audioUrl, isPlaying, isSelected, eq, playbackOffset
    }));
    localStorage.setItem("channels", JSON.stringify(persist));
  }, [channels]);

  const [downloadFormat, setDownloadFormat] = useState("wav");
  const [downloadFilename, setDownloadFilename] = useState("combined");

  const audioContextRef = useRef(null);
  if (!audioContextRef.current) {
    audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
  }
  const channelNodesRef = useRef({});

  const setupAudioNodes = (channelId, audioUrl) => {
    if (channelNodesRef.current[channelId]) return;
    const audio = new Audio(audioUrl);
    audio.crossOrigin = "anonymous";
    audio.onended = () => {
      audio.currentTime = 0;
      setChannels(prev => prev.map(ch => ch.id === channelId ? { ...ch, isPlaying: false } : ch));
    };
    const sourceNode = audioContextRef.current.createMediaElementSource(audio);
    const gainNode = audioContextRef.current.createGain();
    const analyserNode = audioContextRef.current.createAnalyser();
    analyserNode.fftSize = 2048;
    sourceNode.connect(gainNode);
    gainNode.connect(analyserNode);
    const pannerNode = audioContextRef.current.createStereoPanner();
    analyserNode.connect(pannerNode);
    pannerNode.connect(audioContextRef.current.destination);
    channelNodesRef.current[channelId] = { 
      audioElement: audio, 
      gainNode, 
      pannerNode, 
      analyserNode, 
      sourceNode 
    };
  };

  const updateAudioNodes = (channel) => {
    const nodes = channelNodesRef.current[channel.id];
    if (!nodes) return;
    const anySolo = channels.some(ch => ch.isSolo);
    let effectiveVolume = Number(channel.volume) / 100;
    if (channel.isMuted || (anySolo && !channel.isSolo)) effectiveVolume = 0;
    nodes.gainNode.gain.value = effectiveVolume;
    nodes.pannerNode.pan.value = Number(channel.pan) / 50;
  };

  useEffect(() => {
    channels.forEach(ch => {
      if (ch.audioUrl && channelNodesRef.current[ch.id]) {
        updateAudioNodes(ch);
      }
    });
  }, [channels]);

  const nextChannelId = useRef(channels.length ? Math.max(...channels.map(ch => ch.id)) + 1 : 1);
  const addChannel = () => {
    const newChannel = {
      id: nextChannelId.current,
      name: `Channel ${nextChannelId.current}`,
      volume: 50,
      pan: 0,
      isMuted: false,
      isSolo: false,
      inputSource: "microphone",
      waveform: [],
      duration: 0,
      isRecording: false,
      mediaRecorder: null,
      audioUrl: null,
      isPlaying: false,
      isSelected: false,
      playbackOffset: 0,
      eq: JSON.parse(JSON.stringify(initialEQChannels))
    };
    nextChannelId.current += 1;
    setChannels([...channels, newChannel]);
  };

  const removeChannel = (id) => {
    if (!window.confirm("이 채널을 삭제할까요?")) return;
    setChannels(prev => prev.filter(ch => ch.id !== id));
    if (channelNodesRef.current[id]) {
      channelNodesRef.current[id].audioElement.pause();
      delete channelNodesRef.current[id];
    }
  };

  const toggleRecording = async (id) => {
    const channel = channels.find(ch => ch.id === id);
    if (!channel.isRecording) {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        const mediaRecorder = new MediaRecorder(stream);
        let chunks = [];
        mediaRecorder.ondataavailable = (event) => { chunks.push(event.data); };
        mediaRecorder.onstop = async () => {
          const blob = new Blob(chunks, { type: "audio/wav" });
          const audioUrl = URL.createObjectURL(blob);
          const arrayBuffer = await blob.arrayBuffer();
          const ctx = audioContextRef.current;
          const audioBuffer = await ctx.decodeAudioData(arrayBuffer);
          const waveform = extractWaveform(audioBuffer.getChannelData(0));
          setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, audioUrl, duration: audioBuffer.duration, waveform } : ch));
          setupAudioNodes(id, audioUrl);
        };
        mediaRecorder.start();
        setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, isRecording: true, mediaRecorder } : ch));
      } catch (err) {
        console.error("Error accessing audio device:", err);
      }
    } else {
      if (channel.mediaRecorder) channel.mediaRecorder.stop();
      setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, isRecording: false } : ch));
    }
  };

  const handleFileChange = (e, id) => {
    const file = e.target.files[0];
    if (file) {
      const ctx = audioContextRef.current;
      const reader = new FileReader();
      reader.onload = async () => {
        try {
          const arrayBuffer = reader.result;
          if (arrayBuffer instanceof ArrayBuffer) {
            const audioBuffer = await ctx.decodeAudioData(arrayBuffer);
            const duration = audioBuffer.duration;
            const waveform = extractWaveform(audioBuffer.getChannelData(0));
            const newUrl = URL.createObjectURL(file);
            setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, audioUrl: newUrl, duration, waveform } : ch));
            setupAudioNodes(id, newUrl);
          } else {
            console.error("File is not an ArrayBuffer.");
          }
        } catch (err) {
          console.error("Error decoding audio file:", err);
        }
      };
      reader.readAsArrayBuffer(file);
    }
  };

  const handleVolumeChange = (e, id) => {
    const value = Number(e.target.value);
    setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, volume: value } : ch));
  };

  const handlePanChange = (e, id) => {
    const value = Number(e.target.value);
    setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, pan: value } : ch));
  };

  const handleInputSourceChange = (e, id) => {
    const value = e.target.value;
    setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, inputSource: value } : ch));
  };

  const handleNameChange = (e, id) => {
    const value = e.target.value;
    setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, name: value } : ch));
  };

  const handleSelectChange = (e, id) => {
    const checked = e.target.checked;
    setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, isSelected: checked } : ch));
  };

  const toggleMute = (id) => {
    setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, isMuted: !ch.isMuted } : ch));
  };

  const toggleSolo = (id) => {
    setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, isSolo: !ch.isSolo } : ch));
  };

  const playAudio = async (id) => {
    const channel = channels.find(ch => ch.id === id);
    if (!channel.audioUrl) return;
    if (!channelNodesRef.current[id]) setupAudioNodes(id, channel.audioUrl);
    const nodes = channelNodesRef.current[id];
    if (audioContextRef.current.state === "suspended") {
      await audioContextRef.current.resume();
    }
    if (nodes.audioElement.ended || nodes.audioElement.currentTime >= nodes.audioElement.duration) {
      nodes.audioElement.currentTime = 0;
    }
    nodes.audioElement.play();
    setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, isPlaying: true } : ch));
  };

  const pauseAudio = (id) => {
    const nodes = channelNodesRef.current[id];
    if (nodes) nodes.audioElement.pause();
    setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, isPlaying: false } : ch));
  };

  // 타임라인 슬라이더를 통한 재생 위치 제어
  const seekChannel = (id, newTime) => {
    const audioElem = channelNodesRef.current[id]?.audioElement;
    if (audioElem) {
      audioElem.currentTime = newTime;
    }
    setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, playbackOffset: newTime } : ch));
  };

  // EQ 편집 모달 전환: 주파수 캔버스 클릭 시 해당 채널의 EQ 편집 모달 열기
  const [editingEQChannelId, setEditingEQChannelId] = useState(null);
  const handleFrequencyClick = (channelId) => {
    setEditingEQChannelId(channelId);
  };

  // ChannelVisualizer 컴포넌트를 직접 사용하여 그래프 렌더링
  const renderChannelVisualizer = (channel) => {
    return (
      <ChannelVisualizer
        analyser={channelNodesRef.current[channel.id].analyserNode}
        staticWaveform={channel.waveform}
        isPlaying={channel.isPlaying}
        audioElement={channelNodesRef.current[channel.id].audioElement}
        duration={channel.duration}
        isRecording={channel.isRecording}
      />
    );
  };

  const renderTimeline = (channel) => {
    const audioElem = channelNodesRef.current[channel.id]?.audioElement;
    const current = audioElem ? audioElem.currentTime : 0;
    if (!channel.duration || channel.duration <= 0) return null;
    return (
      <div className="main-timeline-container">
        <input
          type="range"
          min="0"
          max={channel.duration}
          step="0.1"
          value={current}
          onChange={(e) => seekChannel(channel.id, parseFloat(e.target.value))}
          className="main-timeline-slider"
        />
      </div>
    );
  };

  return (
    <div className="main-container">
      <div className="main-control-panel">
        <button onClick={() => addChannel()}>Add Channel</button>
      </div>
      {channels.map(channel => (
        <div className="main-channel-strip" key={channel.id}>
          <div className="main-channel-controls">
            <div className="main-channel-header">
              <input
                type="text"
                className="main-channel-name"
                value={channel.name}
                onChange={(e) => handleNameChange(e, channel.id)}
              />
              <button className="main-remove-btn" onClick={() => removeChannel(channel.id)}>
                delete
              </button>
            </div>
            <div className="main-controls">
              <label htmlFor={`select-${channel.id}`}>Select:</label>
              <input
                type="checkbox"
                id={`select-${channel.id}`}
                checked={channel.isSelected || false}
                onChange={(e) => handleSelectChange(e, channel.id)}
              />
            </div>
            <div className="main-controls">
              <label htmlFor={`volume-${channel.id}`}>Volume:</label>
              <input
                type="range"
                id={`volume-${channel.id}`}
                min="0"
                max="100"
                value={channel.volume}
                onChange={(e) => handleVolumeChange(e, channel.id)}
              />
              <span>{channel.volume}</span>
            </div>
            <div className="main-controls">
              <label htmlFor={`pan-${channel.id}`}>Pan:</label>
              <input
                type="range"
                id={`pan-${channel.id}`}
                min="-100"
                max="100"
                value={channel.pan}
                onChange={(e) => handlePanChange(e, channel.id)}
              />
              <span>
                {channel.pan < 0 ? `L ${Math.abs(channel.pan)}` : channel.pan > 0 ? `R ${channel.pan}` : "Center"}
              </span>
            </div>
            <div className="main-controls">
              <label htmlFor={`inputSource-${channel.id}`}>Input:</label>
              <select
                id={`inputSource-${channel.id}`}
                value={channel.inputSource}
                onChange={(e) => handleInputSourceChange(e, channel.id)}
              >
                <option value="microphone">Microphone</option>
                <option value="audioFile">Audio File</option>
                <option value="usb">USB Line Input</option>
              </select>
              {channel.inputSource === "audioFile" && (
                <input type="file" accept="audio/*" onChange={(e) => handleFileChange(e, channel.id)} />
              )}
            </div>
            <button onClick={() => toggleRecording(channel.id)}>
              {channel.isRecording ? "Stop Recording" : "Start Recording"}
            </button>
            {channel.audioUrl && (
              <div className="main-playback-controls">
                {channel.isPlaying ? (
                  <button onClick={() => pauseAudio(channel.id)}>Pause</button>
                ) : (
                  <button onClick={() => playAudio(channel.id)}>Play</button>
                )}
              </div>
            )}
            <button className="main-mute-btn" onClick={() => toggleMute(channel.id)}>
              {channel.isMuted ? "Unmute" : "Mute"}
            </button>
            <button className="main-solo-btn" onClick={() => toggleSolo(channel.id)}>
              {channel.isSolo ? "Unsolo" : "Solo"}
            </button>
          </div>
          <div className="main-channel-visualizer">
            {channel.audioUrl &&
            channelNodesRef.current[channel.id] &&
            channelNodesRef.current[channel.id].analyserNode ? (
              <>
                {renderChannelVisualizer(channel)}
                {renderTimeline(channel)}
              </>
            ) : (
              <div style={{ width: "1350px", height: "300px", border: "1px solid #444", display: "flex", alignItems: "center", justifyContent: "center", backgroundColor: "#111" }}>
                오디오 파일을 업로드하거나, 녹음을 진행하세요.
              </div>
            )}
          </div>
        </div>
      ))}
      <div className="main-combine-section">
        <div className="combine-options">
          <label>
            File Format:
            <select value={downloadFormat} onChange={(e) => setDownloadFormat(e.target.value)}>
              <option value="wav">WAV</option>
              <option value="mp3">MP3</option>
            </select>
          </label>
          <label>
            File Name:
            <input type="text" value={downloadFilename} onChange={(e) => setDownloadFilename(e.target.value)} />
          </label>
        </div>
        <button
          onClick={async () => {
            const selectedChannels = channels.filter(ch => ch.isSelected);
            if (selectedChannels.length === 0) {
              alert("Please select at least one channel to combine.");
              return;
            }
            const ctx = audioContextRef.current;
            const buffers = await Promise.all(selectedChannels.map(ch => loadAudioBuffer(ch.audioUrl, ctx)));
            const maxDuration = Math.max(...buffers.map(buf => buf.duration));
            const sr = ctx.sampleRate;
            const length = Math.floor(maxDuration * sr);
            const offlineCtx = new OfflineAudioContext(1, length, sr);
            buffers.forEach(buffer => {
              const source = offlineCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(offlineCtx.destination);
              source.start(0);
            });
            const renderedBuffer = await offlineCtx.startRendering();
            if (downloadFormat === "mp3") {
              alert("MP3 변환은 현재 지원되지 않습니다. WAV 형식으로 다운로드됩니다.");
            }
            const wavBlob = bufferToWave(renderedBuffer, renderedBuffer.length);
            const url = URL.createObjectURL(wavBlob);
            const a = document.createElement("a");
            a.style.display = "none";
            a.href = url;
            a.download = `${downloadFilename || "combined"}.wav`;
            document.body.appendChild(a);
            a.click();
            setTimeout(() => {
              document.body.removeChild(a);
              window.URL.revokeObjectURL(url);
            }, 100);
          }}
        >
          Combine Selected Channels
        </button>
      </div>
      {editingEQChannelId && (
        <div className="eq-overlay">
          <EqualizerEditor
            channel={channels.find(ch => ch.id === editingEQChannelId)}
            onApply={(newEQ) => {
              setChannels(prev =>
                prev.map(ch =>
                  ch.id === editingEQChannelId ? { ...ch, eq: newEQ } : ch
                )
              );
              setEditingEQChannelId(null);
            }}
            onCancel={() => setEditingEQChannelId(null)}
          />
        </div>
      )}
    </div>
  );
};

export default Main;
