import React, { useState, useEffect, useRef } from 'react';
import './equalizer.css';

// 샘플레이트 (44100 Hz 고정)
const sampleRate = 44100;

// 초기 EQ 채널 설정  
// 순서: Low‑cut, Low, Low‑mid, Mid, High‑mid, High, Presence, High‑cut  
const initialEQChannels = [
  { name: "Low-cut", freq: 20,   Q: 0.7, gain: 0, enabled: true, color: "#1abc9c" },
  { name: "Low",     freq: 100,  Q: 1.0, gain: 0, eqMode: "PEQ", color: "#3498db" },
  { name: "Low-mid", freq: 500,  Q: 1.0, gain: 0, eqMode: "PEQ", color: "#9b59b6" },
  { name: "Mid",     freq: 800, Q: 1.0, gain: 0, eqMode: "PEQ", color: "#e67e22" },
  { name: "High-mid",freq: 1000, Q: 1.0, gain: 0, eqMode: "PEQ", color: "#e74c3c" },
  { name: "High",    freq: 4000, Q: 1.0, gain: 0, eqMode: "PEQ", color: "#f1c40f" },
  { name: "Presence",freq: 8000, Q: 1.0, gain: 0, eqMode: "PEQ", color: "#2ecc71" },
  { name: "High-cut",freq: 12000, Q: 0.7, gain: 0, enabled: true, color: "#95a5a6" }
];

const defaultColorPalette = ["#1abc9c", "#3498db", "#9b59b6", "#e67e22", "#e74c3c", "#f1c40f", "#2ecc71", "#95a5a6"];

/* ── Fader 컴포넌트 ──
   슬라이더와 함께 숫자 입력 필드를 통합하여 값 조절 */
const Fader = ({ value, min, max, step, onChange, label, unit }) => {
  const handleChange = (val) => {
    onChange(parseFloat(val));
  };

  return (
    <div className="fader-container">
      <div className="fader-label">{label}</div>
      <input
        type="range"
        className="fader-input"
        value={value}
        min={min}
        max={max}
        step={step}
        onChange={(e) => handleChange(e.target.value)}
      />
      {/* 숫자 입력 필드 */}
      <input
        type="number"
        className="fader-number"
        value={value}
        min={min}
        max={max}
        step={step}
        onChange={(e) => handleChange(e.target.value)}
      />
      <div className="fader-unit">{unit}</div>
    </div>
  );
};

/* ── Equalizer 컴포넌트 ── */
const Equalizer = () => {
  const [audioSourceType, setAudioSourceType] = useState('file');
  const [audioFile, setAudioFile] = useState(null);
  const [eqChannels, setEQChannels] = useState(initialEQChannels);
  const [compressorSettings, setCompressorSettings] = useState({
    threshold: -24,
    ratio: 12,
    attack: 0.003,
    release: 0.25,
  });
  const [isPlaying, setIsPlaying] = useState(false);
  const [playbackOffset, setPlaybackOffset] = useState(0);
  const [volume, setVolume] = useState(-0.1);
  const [fileDuration, setFileDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  // Web Audio API 관련 refs
  const audioContextRef = useRef(null);
  const sourceRef = useRef(null);
  const analyserRef = useRef(null);
  const eqNodesRef = useRef([]);
  const compressorRef = useRef(null);
  const animationIdRef = useRef(null);
  const canvasRef = useRef(null);
  // 캔버스 드래그용: 활성화된 채널 인덱스
  const eqChannelsRef = useRef(eqChannels);
  useEffect(() => { eqChannelsRef.current = eqChannels; }, [eqChannels]);

  // 파일 재생 관련 refs
  const fileAudioBufferRef = useRef(null);
  const fileSourceRef = useRef(null);
  const playbackStartTimeRef = useRef(0);
  const volumeGainRef = useRef(null);

  // 타임라인 업데이트용 인터벌 ref
  const timelineIntervalRef = useRef(null);

  const closeAudioContext = async () => {
    if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
      try { await audioContextRef.current.close(); }
      catch (err) { console.error('AudioContext 닫기 오류:', err); }
    }
  };

  /* ── EQ 응답 곡선 계산 함수 ── */
  const getPeakingResponse = (ch, f) => {
    const A = Math.pow(10, ch.gain / 40);
    const omega0 = 2 * Math.PI * ch.freq / sampleRate;
    const alpha = Math.sin(omega0) / (2 * ch.Q);
    const b0 = 1 + alpha * A;
    const b1 = -2 * Math.cos(omega0);
    const b2 = 1 - alpha * A;
    const a0 = 1 + alpha / A;
    const a1 = -2 * Math.cos(omega0);
    const a2 = 1 - alpha / A;
    const omega = 2 * Math.PI * f / sampleRate;
    const cos_omega = Math.cos(omega);
    const sin_omega = Math.sin(omega);
    const cos_2omega = Math.cos(2 * omega);
    const sin_2omega = Math.sin(2 * omega);
    const numReal = b0 + b1 * cos_omega + b2 * cos_2omega;
    const numImag = -(b1 * sin_omega + b2 * sin_2omega);
    const denReal = a0 + a1 * cos_omega + a2 * cos_2omega;
    const denImag = -(a1 * sin_omega + a2 * sin_2omega);
    const mag = Math.sqrt((numReal ** 2 + numImag ** 2) / (denReal ** 2 + denImag ** 2));
    return 20 * Math.log10(mag);
  };

  const getHighpassResponse = (ch, f) => {
    const effectiveQ = (ch.name === "Low-cut") ? 0.7 : ch.Q;
    const omega0 = 2 * Math.PI * ch.freq / sampleRate;
    const alpha = Math.sin(omega0) / (2 * effectiveQ);
    const b0 = (1 + Math.cos(omega0)) / 2;
    const b1 = -(1 + Math.cos(omega0));
    const b2 = (1 + Math.cos(omega0)) / 2;
    const a0 = 1 + alpha;
    const a1 = -2 * Math.cos(omega0);
    const a2 = 1 - alpha;
    const omega = 2 * Math.PI * f / sampleRate;
    const numReal = b0 + b1 * Math.cos(omega) + b2 * Math.cos(2 * omega);
    const numImag = -(b1 * Math.sin(omega) + b2 * Math.sin(2 * omega));
    const denReal = a0 + a1 * Math.cos(omega) + a2 * Math.cos(2 * omega);
    const denImag = -(a1 * Math.sin(omega) + a2 * Math.sin(2 * omega));
    const mag = Math.sqrt((numReal ** 2 + numImag ** 2) / (denReal ** 2 + denImag ** 2));
    return 20 * Math.log10(mag);
  };

  const getLowpassResponse = (ch, f) => {
    const effectiveQ = (ch.name === "High-cut") ? 0.7 : ch.Q;
    const omega0 = 2 * Math.PI * ch.freq / sampleRate;
    const alpha = Math.sin(omega0) / (2 * effectiveQ);
    const b0 = (1 - Math.cos(omega0)) / 2;
    const b1 = 1 - Math.cos(omega0);
    const b2 = (1 - Math.cos(omega0)) / 2;
    const a0 = 1 + alpha;
    const a1 = -2 * Math.cos(omega0);
    const a2 = 1 - alpha;
    const omega = 2 * Math.PI * f / sampleRate;
    const numReal = b0 + b1 * Math.cos(omega) + b2 * Math.cos(2 * omega);
    const numImag = -(b1 * Math.sin(omega) + b2 * Math.sin(2 * omega));
    const denReal = a0 + a1 * Math.cos(omega) + a2 * Math.cos(2 * omega);
    const denImag = -(a1 * Math.sin(omega) + a2 * Math.sin(2 * omega));
    const mag = Math.sqrt((numReal ** 2 + numImag ** 2) / (denReal ** 2 + denImag ** 2));
    return 20 * Math.log10(mag);
  };

  // 수정된 Shelf 응답 함수  
  // Lo-shelf: f가 f₀보다 낮을 때 gain 적용, f가 높으면 효과 0
  const getLoShelfResponse = (ch, f) => {
    const gainDB = ch.gain; 
    const f0 = ch.freq;
    const k = 10;
    // f << f0 → ratio ~1, f >> f0 → ratio ~0
    const ratio = 1 / (1 + Math.exp(k * (Math.log(f) - Math.log(f0))));
    return gainDB * ratio;
  };

  // Hi-shelf: f가 f₀보다 높을 때 gain 적용, f가 낮으면 효과 0
  const getHiShelfResponse = (ch, f) => {
    const gainDB = ch.gain;
    const f0 = ch.freq;
    const k = 10;
    // f << f0 → ratio ~0, f >> f0 → ratio ~1
    const ratio = 1 / (1 + Math.exp(-k * (Math.log(f) - Math.log(f0))));
    return gainDB * ratio;
  };

  // EQ 응답 계산: VEQ와 PEQ, Shelf 차별화 적용
  const getEQResponse = (ch, f) => {
    if (ch.name === "Low-cut") return getHighpassResponse(ch, f);
    else if (ch.name === "High-cut") return getLowpassResponse(ch, f);
    else {
      const mode = ch.eqMode || "PEQ";
      if (mode === "Lo-shelf") return getLoShelfResponse(ch, f);
      else if (mode === "Hi-shelf") return getHiShelfResponse(ch, f);
      else if (mode === "VEQ") {
        // VEQ: PEQ 응답에 exponent 1.5 적용
        const peq = getPeakingResponse(ch, f);
        const baseline = 0;
        const delta = peq - baseline;
        const modified = baseline + Math.sign(delta) * Math.pow(Math.abs(delta), 1.5);
        return modified;
      } else { // PEQ
        return getPeakingResponse(ch, f);
      }
    }
  };

  // ── 캔버스 시각화 및 EQ 커브 오버레이 ──
  const drawVisualizer = () => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const analyser = analyserRef.current;
    const bufferLength = analyser.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);
    const WIDTH = canvas.width;
    const HEIGHT = canvas.height;
    const numPoints = 200;

    const draw = () => {
      analyser.getByteFrequencyData(dataArray);
      // 오디오 주파수 스펙트럼 그리기
      ctx.clearRect(0, 0, WIDTH, HEIGHT);
      const barWidth = (WIDTH / bufferLength) * 2.5;
      let x = 0;
      for (let i = 0; i < bufferLength; i++) {
        const barHeight = (dataArray[i] / 255) * HEIGHT;
        ctx.fillStyle = "rgba(255,255,255,0.15)";
        ctx.fillRect(x, HEIGHT - barHeight, barWidth, barHeight);
        x += barWidth + 1;
      }
      
      // 반투명 EQ 그래프 영역 배경
      ctx.fillStyle = "rgba(34,34,34,0.5)";
      ctx.fillRect(0, 0, WIDTH, HEIGHT);
      
      // X축 (주파수) 마커
      const xMarkers = [20, 40, 60, 100, 200, 400, 600, 1000, 2000, 3000, 4000, 5000, 6000, 10000, 20000];
      ctx.fillStyle = "#ccc";
      ctx.font = "10px Arial";
      ctx.textAlign = "center";
      xMarkers.forEach(f => {
        const xPos = Math.log(f / 20) / Math.log(20000 / 20) * WIDTH;
        ctx.fillText(f, xPos, HEIGHT - 2);
        ctx.beginPath();
        ctx.moveTo(xPos, HEIGHT);
        ctx.lineTo(xPos, HEIGHT - 5);
        ctx.strokeStyle = "#ccc";
        ctx.stroke();
      });
      
      // Y축 (dB) 마커
      const yMarkers = [-15, -10, -5, 0, 5, 10, 15];
      ctx.textAlign = "right";
      yMarkers.forEach(db => {
        const yPos = ((15 - db) / 30) * HEIGHT;
        ctx.fillText(db + " dB", 30, yPos + 3);
        ctx.beginPath();
        ctx.moveTo(32, yPos);
        ctx.lineTo(37, yPos);
        ctx.strokeStyle = "#ccc";
        ctx.stroke();
      });
      
      // 각 EQ 채널별 응답 곡선 오버레이
      eqChannelsRef.current.forEach((ch) => {
        const points = [];
        for (let i = 0; i < numPoints; i++){
          const frac = i / (numPoints - 1);
          const f = 20 * Math.pow(20000 / 20, frac);
          const response = getEQResponse(ch, f);
          const yVal = ((15 - response) / 30) * HEIGHT;
          const xVal = Math.log(f / 20) / Math.log(20000 / 20) * WIDTH;
          points.push({ x: xVal, y: yVal });
        }
        // 채우기 영역: 곡선과 0 dB 라인(HEIGHT*0.5) 사이
        ctx.beginPath();
        points.forEach((pt, idx) => {
          if (idx === 0) ctx.moveTo(pt.x, pt.y);
          else ctx.lineTo(pt.x, pt.y);
        });
        ctx.lineTo(points[points.length - 1].x, 0.5 * HEIGHT);
        ctx.lineTo(points[0].x, 0.5 * HEIGHT);
        ctx.closePath();
        ctx.fillStyle = ch.color;
        ctx.globalAlpha = 0.3;
        ctx.fill();
        ctx.globalAlpha = 1.0;
        
        // 커브 선 그리기
        ctx.beginPath();
        points.forEach((pt, idx) => {
          if (idx === 0) ctx.moveTo(pt.x, pt.y);
          else ctx.lineTo(pt.x, pt.y);
        });
        ctx.strokeStyle = ch.color;
        ctx.lineWidth = 2;
        ctx.stroke();
        
        // 채널 중심 포인트
        const xMid = Math.log(ch.freq / 20) / Math.log(20000 / 20) * WIDTH;
        const yMid = ((15 - ch.gain) / 30) * HEIGHT;
        ctx.beginPath();
        ctx.arc(xMid, yMid, 6, 0, Math.PI * 2);
        ctx.fillStyle = ch.color;
        ctx.fill();
        ctx.font = "10px Arial";
        ctx.textAlign = "left";
        ctx.fillStyle = "#fff";
        ctx.fillText(`F:${ch.freq}Hz`, xMid + 8, yMid - 10);
        ctx.fillText(`Q:${ch.Q}`, xMid + 8, yMid);
        ctx.fillText(`G:${ch.gain}`, xMid + 8, yMid + 12);
      });
      
      animationIdRef.current = requestAnimationFrame(draw);
    };
    draw();
  };

  // ── 캔버스에서 드래그 및 휠 이벤트 처리 (EQ 파라미터 조절) ──
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const WIDTH = canvas.width;
    const HEIGHT = canvas.height;
    let activeIndex = null;
    
    const onMouseDown = (e) => {
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      eqChannelsRef.current.forEach((ch, idx) => {
        const xMid = Math.log(ch.freq / 20) / Math.log(20000 / 20) * WIDTH;
        const yMid = ((15 - ch.gain) / 30) * HEIGHT;
        const dist = Math.hypot(x - xMid, y - yMid);
        if (dist < 8) {
          activeIndex = idx;
        }
      });
    };
    
    const onMouseMove = (e) => {
      if (activeIndex === null) return;
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      let newFreq = 20 * Math.pow(20000 / 20, x / WIDTH);
      let newGain = 15 - (y / HEIGHT) * 30;
      newFreq = Math.min(20000, Math.max(20, newFreq));
      newGain = Math.min(15, Math.max(-15, newGain));
      const newChannels = [...eqChannelsRef.current];
      newChannels[activeIndex] = { 
        ...newChannels[activeIndex], 
        freq: parseFloat(newFreq.toFixed(0)), 
        gain: parseFloat(newGain.toFixed(1))
      };
      setEQChannels(newChannels);
    };
    
    const onMouseUp = () => { activeIndex = null; };

    // 휠 이벤트로 Q값 조절 (마우스가 채널 포인트 근처에서만 작동)
    const onWheel = (e) => {
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      let foundIndex = null;
      eqChannelsRef.current.forEach((ch, idx) => {
        const xMid = Math.log(ch.freq / 20) / Math.log(20000 / 20) * WIDTH;
        const yMid = ((15 - ch.gain) / 30) * HEIGHT;
        const dist = Math.hypot(x - xMid, y - yMid);
        if (dist < 10) {
          foundIndex = idx;
        }
      });
      if (foundIndex !== null) {
        e.preventDefault();
        let newQ = eqChannelsRef.current[foundIndex].Q - e.deltaY * 0.01;
        newQ = Math.min(10, Math.max(0, newQ));
        const newChannels = [...eqChannelsRef.current];
        newChannels[foundIndex] = { 
          ...newChannels[foundIndex], 
          Q: parseFloat(newQ.toFixed(2)) 
        };
        setEQChannels(newChannels);
      }
    };

    canvas.addEventListener('mousedown', onMouseDown);
    canvas.addEventListener('mousemove', onMouseMove);
    canvas.addEventListener('wheel', onWheel, { passive: false });
    window.addEventListener('mouseup', onMouseUp);
    return () => {
      canvas.removeEventListener('mousedown', onMouseDown);
      canvas.removeEventListener('mousemove', onMouseMove);
      canvas.removeEventListener('wheel', onWheel);
      window.removeEventListener('mouseup', onMouseUp);
    };
  }, []);

  // ── 오디오 체인 구성 ──
  const setupAudio = async () => {
    await closeAudioContext();
    const AudioContext = window.AudioContext || window.webkitAudioContext;
    const audioContext = new AudioContext();
    audioContextRef.current = audioContext;
    
    const analyser = audioContext.createAnalyser();
    analyser.fftSize = 2048;
    analyserRef.current = analyser;
    
    // 각 EQ 채널에 대해 필터 노드 생성
    eqNodesRef.current = eqChannels.map((ch) => {
      let filter;
      if (ch.name === "Low-cut") {
        filter = audioContext.createBiquadFilter();
        filter.type = 'highpass';
      } else if (ch.name === "High-cut") {
        filter = audioContext.createBiquadFilter();
        filter.type = 'lowpass';
      } else {
        filter = audioContext.createBiquadFilter();
        filter.type = 'peaking';
      }
      filter.frequency.value = ch.freq;
      filter.Q.value = ch.Q;
      // VEQ와 PEQ 차별화: VEQ는 gain에 1.2배 보정 적용
      filter.gain.value = (ch.eqMode === "VEQ") ? ch.gain * 1.2 : ch.gain;
      return filter;
    });
    
    for (let i = 0; i < eqNodesRef.current.length - 1; i++) {
      eqNodesRef.current[i].connect(eqNodesRef.current[i+1]);
    }
    eqNodesRef.current[eqNodesRef.current.length - 1].connect(analyser);
    analyser.connect(audioContext.destination);
    
    if (audioSourceType === 'mic' || audioSourceType === 'usb') {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        const source = audioContext.createMediaStreamSource(stream);
        source.connect(eqNodesRef.current[0]);
        sourceRef.current = source;
      } catch (err) {
        console.error('마이크/USB 오디오 접근 오류:', err);
      }
    } else if (audioSourceType === 'file' && audioFile) {
      const reader = new FileReader();
      reader.onload = async (e) => {
        const arrayBuffer = e.target.result;
        try {
          const audioBuffer = await audioContext.decodeAudioData(arrayBuffer);
          fileAudioBufferRef.current = audioBuffer;
          setFileDuration(audioBuffer.duration);
          const volGain = audioContext.createGain();
          volGain.gain.value = volume;
          volumeGainRef.current = volGain;
          volGain.connect(eqNodesRef.current[0]);
        } catch (err) {
          console.error('음악 파일 디코딩 오류:', err);
        }
      };
      reader.readAsArrayBuffer(audioFile);
    }
    
    if (canvasRef.current && analyserRef.current) {
      drawVisualizer();
    }
  };

  useEffect(() => {
    if (audioSourceType === 'file') {
      setPlaybackOffset(0);
      setIsPlaying(false);
      fileAudioBufferRef.current = null;
      fileSourceRef.current = null;
    }
    setupAudio();
    return () => {
      if (animationIdRef.current) cancelAnimationFrame(animationIdRef.current);
      closeAudioContext();
    };
  }, [audioSourceType, audioFile]);

  useEffect(() => {
    if (eqNodesRef.current.length === eqChannels.length) {
      eqNodesRef.current.forEach((filter, idx) => {
        const ch = eqChannels[idx];
        filter.frequency.value = ch.freq;
        filter.Q.value = ch.Q;
        filter.gain.value = (ch.eqMode === "VEQ") ? ch.gain * 1.2 : ch.gain;
      });
    }
  }, [eqChannels]);

  // ── 파일 재생 및 타임라인 컨트롤 ──
  const playFile = async () => {
    if (!fileAudioBufferRef.current || !audioContextRef.current) return;
    if (isPlaying) return;
    const audioContext = audioContextRef.current;
    await audioContext.resume();
    const source = audioContext.createBufferSource();
    source.buffer = fileAudioBufferRef.current;
    source.loop = true;
    if (volumeGainRef.current) source.connect(volumeGainRef.current);
    else source.connect(eqNodesRef.current[0]);
    fileSourceRef.current = source;
    playbackStartTimeRef.current = audioContext.currentTime - playbackOffset;
    source.start(0, playbackOffset);
    setIsPlaying(true);
    timelineIntervalRef.current = setInterval(() => {
      const newTime = audioContext.currentTime - playbackStartTimeRef.current;
      setCurrentTime(newTime);
    }, 200);
  };

  const pauseFile = () => {
    if (!isPlaying || !fileSourceRef.current || !audioContextRef.current) return;
    const audioContext = audioContextRef.current;
    const elapsed = audioContext.currentTime - playbackStartTimeRef.current;
    setPlaybackOffset(playbackOffset + elapsed);
    try {
      fileSourceRef.current.stop();
    } catch (e) {
      console.error('소스 중지 오류:', e);
    }
    setIsPlaying(false);
    if (timelineIntervalRef.current) clearInterval(timelineIntervalRef.current);
  };

  const skipForward = () => {
    const newOffset = playbackOffset + 5;
    if (isPlaying) {
      pauseFile();
      setPlaybackOffset(newOffset);
      setTimeout(() => { playFile(); }, 0);
    } else {
      setPlaybackOffset(newOffset);
    }
  };

  const skipBackward = () => {
    const newOffset = Math.max(0, playbackOffset - 5);
    if (isPlaying) {
      pauseFile();
      setPlaybackOffset(newOffset);
      setTimeout(() => { playFile(); }, 0);
    } else {
      setPlaybackOffset(newOffset);
    }
  };

  // 개별 EQ 채널 초기화 (Reset)
  const resetEQChannel = (index) => {
    const newEQChannels = [...eqChannels];
    newEQChannels[index] = { ...initialEQChannels[index] };
    setEQChannels(newEQChannels);
  };

  // 전체 EQ 채널 초기화
  const resetAllEQChannels = () => {
    setEQChannels([...initialEQChannels]);
  };

  // EQ 채널 추가 (새로운 채널 기본값)
  const addEQChannel = () => {
    const newChannel = { 
      name: "New Channel", 
      freq: 1000, 
      Q: 1.0, 
      gain: 0, 
      eqMode: "PEQ",
      color: defaultColorPalette[eqChannels.length % defaultColorPalette.length]
    };
    setEQChannels(prev => [...prev, newChannel]);
  };

  // EQ 채널 삭제
  const deleteEQChannel = (index) => {
    setEQChannels(prev => prev.filter((_, idx) => idx !== index));
  };

  const handleSourceChange = (e) => { setAudioSourceType(e.target.value); };
  const handleFileChange = (e) => { if (e.target.files.length > 0) setAudioFile(e.target.files[0]); };

  // ── EQ 채널 업데이트 핸들러 ──
  // EQ 채널 업데이트 핸들러
const handleEQChannelChange = (idx, key, val) => {
  const defaultValues = {
    freq: initialEQChannels[idx].freq,
    Q: initialEQChannels[idx].Q,
    gain: initialEQChannels[idx].gain
  };

  const newValue = isNaN(val) || val === "" || val === null ? defaultValues[key] : parseFloat(val);

  setEQChannels(prev => {
    const newArr = [...prev];
    newArr[idx] = { ...newArr[idx], [key]: newValue };
    return newArr;
  });
};

  return (
    <div className="eq-main-container">
      {/* 파일 재생 관련 컨트롤 (하단) */}
      {audioSourceType === 'file' && (
        <div className="eq-file-controls">
          <h2>Music Player Controls</h2>
          <div className="eq-player-buttons">
            <button onClick={playFile} disabled={isPlaying || !fileAudioBufferRef.current}>Play</button>
            <button onClick={pauseFile} disabled={!isPlaying}>Pause</button>
            <button onClick={skipBackward} disabled={!fileAudioBufferRef.current}>-5s</button>
            <button onClick={skipForward} disabled={!fileAudioBufferRef.current}>+5s</button>
          </div>
          <div className="eq-timeline">
            <input 
              type="range"
              className="eq-timeline-slider"
              min="0"
              max={fileDuration}
              step="0.1"
              value={currentTime}
              onChange={(e) => {
                const newTime = parseFloat(e.target.value);
                setCurrentTime(newTime);
                if (isPlaying) {
                  pauseFile();
                  setPlaybackOffset(newTime);
                  setTimeout(() => { playFile(); }, 0);
                } else {
                  setPlaybackOffset(newTime);
                }
              }}
            />
            <span className="eq-time-display">{currentTime.toFixed(1)} / {fileDuration.toFixed(1)} sec</span>
          </div>
        </div>
      )}
      {/* 오디오 소스 선택 및 파일 input */}
      <div className="eq-controls">
        <label htmlFor="source-select">Inout source</label>
        <select id="source-select" value={audioSourceType} onChange={handleSourceChange}>
          <option value="mic">Hardware Mic</option>
          <option value="file">Music File(MP3,WAV)</option>
          <option value="usb">USB Line Connect</option>
        </select>
        {audioSourceType === 'file' && (
          <input type="file" accept="audio/*" onChange={handleFileChange} />
        )}
      </div>
      
      <canvas ref={canvasRef} className="eq-visualizer" width="1400" height="400"></canvas>
      
      {/* EQ 채널 컨트롤 영역 (타이틀 삭제) */}
      <div className="eq-controls">
        <div className="eq-channel-grid">
          {eqChannels.map((ch, idx) => (
            <div key={idx} className="eq-channel" style={{ borderColor: ch.color }}>
              {/* 채널 이름 수정 가능 */}
              <input 
                type="text" 
                className="eq-channel-name" 
                value={ch.name} 
                onChange={(e) => handleEQChannelChange(idx, 'name', e.target.value)}
              />
              {/* Low‑cut과 High‑cut은 on/off 토글 */}
              {(ch.name === "Low-cut" || ch.name === "High-cut") && (
                <div className="eq-toggle-control">
                  <label>
                    <input
                      type="checkbox"
                      checked={ch.enabled}
                      onChange={(e) => handleEQChannelChange(idx, 'enabled', e.target.checked)}
                    />
                    Active
                  </label>
                </div>
              )}
              {/* 모드 선택: Low‑cut과 High‑cut은 선택 불가 */}
              {(ch.name !== "Low-cut" && ch.name !== "High-cut") && (
                <select
                  className="eq-mode-select"
                  value={ch.eqMode || "PEQ"}
                  onChange={(e) => handleEQChannelChange(idx, 'eqMode', e.target.value)}
                >
                  <option value="VEQ">VEQ</option>
                  <option value="PEQ">PEQ</option>
                  <option value="Lo-shelf">Lo-shelf</option>
                  <option value="Hi-shelf">Hi-shelf</option>
                </select>
              )}
              <div className="eq-fader-row">
                <Fader 
                  value={ch.freq} 
                  min={20} 
                  max={20000} 
                  step={1}
                  onChange={(val) => { handleEQChannelChange(idx, 'freq', val); }}
                  label="Freq"
                  unit="Hz"
                />
                <Fader 
                  value={ch.Q} 
                  min={0} 
                  max={10} 
                  step={0.1}
                  onChange={(val) => { handleEQChannelChange(idx, 'Q', val); }}
                  label="Q"
                  unit=""
                />
                <Fader 
                  value={ch.gain} 
                  min={-15} 
                  max={15} 
                  step={0.5}
                  onChange={(val) => { handleEQChannelChange(idx, 'gain', val); }}
                  label="Gain"
                  unit="dB"
                />
              </div>
              <div className="eq-values">
                <span>Freq: {ch.freq} Hz</span>
                <span>Q: {ch.Q}</span>
                <span>Gain: {ch.gain} dB</span>
              </div>
              <div className="eq-channel-buttons">
                <button onClick={() => resetEQChannel(idx)} className="eq-reset-button">초기화</button>
                <button onClick={() => deleteEQChannel(idx)} className="eq-delete-button">삭제</button>
              </div>
            </div>
          ))}
        </div>
        {/* 전체 초기화 및 채널 추가 버튼 (하단 고정) */}
        <div className="eq-global-buttons">
          <button onClick={resetAllEQChannels} className="eq-reset-all-button">전체 초기화</button>
          <button onClick={addEQChannel} className="eq-add-button">채널 추가</button>
        </div>
      </div>
    </div>
  );
};

export default Equalizer;
