import React from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import Nav from './Components/nav/nav';
import ReverbTwo from './Components/reverbtwo/reverbtwo';
import Equalizer from './Components/equalizer/equalizer';
import Channel from './Components/main/main';
import Comp from './Components/comp/comp';
import Reverb from './Components/reverb/reverb';
import DisplayAds from './Components/AD/ad';
import Start from './Components/start/start'; // Start 페이지는 대문자로 수정

function App() {
  return (
    <Router>
      <div>
        <Nav /> {/* Nav는 항상 표시되는 네비게이션 바 */}
        <Routes>
          {/* 각 페이지 컴포넌트는 Route로 감싸서 해당 경로로 이동 시 표시 */}
          <Route path="/start" element={<Start />} />
          <Route path="/reverb" element={<Reverb />} />
          <Route path="/comp" element={<Comp />} />
          <Route path="/equalizer" element={<Equalizer />} />
          <Route path="/reverbtwo" element={<ReverbTwo />} />
          <Route path="/main" element={<Channel />} />
          <Route path="/" element={<Start />} /> {/* 기본적으로 시작 페이지는 Start */}
        </Routes>

        <div className="grid place-content-center">
          {/* 구글 디스플레이 광고 삽입 */}
          <DisplayAds />
          {/* 구글 디스플레이 광고 삽입 */}
        </div>
      </div>
    </Router>
  );
}

export default App;
