import React, { useState, useEffect } from 'react';
import './comp.css';

const Comp = () => {
  /**
   * 컴프레서 파라미터
   * (요청하신 기본값, 최솟값, 최댓값에 맞춰 설정)
   */
  const [attack, setAttack] = useState(24);       // (기본값 24ms, 0~120)
  const [hold, setHold] = useState(0.2);          // (기본값 0.20ms, 0.02~2000)
  const [release, setRelease] = useState(19);     // (기본값 19ms, 5~4000)
  const [ratio, setRatio] = useState(1.1);        // (기본값 1.1:1, 1.1~100)
  const [threshold, setThreshold] = useState(-60); // (기본값 -60dB, -60~0)
  const [knee, setKnee] = useState(0);            // (기본값 0, 0~5)
  const [gain, setGain] = useState(0);            // (기본값 0dB, 0~24)
  const [mix, setMix] = useState(100);            // (기본값 100%, 0~100)

  // Hover 중인 컨트롤 식별자
  const [activeControl, setActiveControl] = useState('');

  /**
   * 각 컨트롤에 대한 상세 설명
   * (초보자도 이해하기 쉽게, 조금 더 자세하게 작성)
   */
  const controlDescriptions = {
    attack: `Attack (ms): 컴프레서가 소리를 감지해 압축을 시작하기까지 걸리는 시간입니다. 
             값이 낮으면 신호가 Threshold를 초과하자마자 빠르게 압축되고, 
             값이 크면 조금 더 부드럽게 압축이 시작됩니다.`,

    hold: `Hold (ms): 압축이 시작된 후, 설정된 시간만큼 압축 상태를 유지합니다. 
           신호가 들쭉날쭉할 때 값을 늘리면 압축이 안정적으로 유지되어 
           빠르게 꺼졌다 켜지는 현상을 줄일 수 있습니다.`,

    release: `Release (ms): 압축된 상태에서 원래 볼륨으로 돌아가는 데 걸리는 시간입니다. 
               값이 짧으면 빨리 복귀해 타격감이 강해질 수 있고, 
               길면 자연스럽게 복귀되어 부드러운 느낌을 줍니다.`,

    ratio: `Ratio (n:n): Threshold를 넘어선 신호가 얼마나 세게 압축될지를 결정합니다. 
            예: 2:1은 Threshold를 초과한 신호를 절반으로 줄이고, 
            10:1 이상이면 매우 강하게 압축됩니다. 
            여기서는 1.1:1부터 100:1까지 설정할 수 있습니다.`,

    threshold: `Threshold (dB): 이 레벨을 초과하는 신호에 대해 압축이 작동합니다. 
                -60dB에 가깝게 설정하면 아주 작은 소리까지 압축되고, 
                0dB 쪽에 가까우면 큰 소리에만 압축이 적용됩니다.`,

    knee: `Knee (dB): Threshold 근처에서 압축이 시작되는 지점을 
           얼마나 부드럽게 연결할지 결정합니다. 
           0dB면 하드 니(Hard Knee)로 갑자기 꺾이고, 
           값이 클수록 완만하게 이어져 자연스러운 압축이 됩니다.`,

    gain: `Gain (dB): 압축으로 인해 줄어든 음량을 보정하기 위해 
           최종 출력 볼륨을 높이거나 낮추는 기능입니다. 
           '메이크업 게인(Make-up Gain)'이라고도 부릅니다.`,

    mix: `Mix (%): 압축된 소리(Wet)와 원본 소리(Dry)의 비율을 조정합니다. 
          100%면 완전히 압축된 소리만, 0%면 원본 소리만 들립니다. 
          병렬 압축(Parallel Compression)을 구현할 때 사용합니다.`
  };

  /**
   * 현실적인 컴프레서 스테틱 Transfer Curve 계산
   * - Knee, Threshold, Ratio, Gain, Mix에 따라
   *   "입력 dB -> 출력 dB" 관계를 결정
   * - Attack/Hold/Release는 실제 오디오 처리 시
   *   시간 기반으로 동작하지만, 여기서는 곡선에 직접 반영하지 않음
   */
  const compressorTransfer = (inputDb) => {
    let outputDb;

    // Knee가 0이면 하드 니
    if (knee === 0) {
      if (inputDb < threshold) {
        outputDb = inputDb;
      } else {
        // ratio 압축
        outputDb = threshold + (inputDb - threshold) / ratio;
      }
    } else {
      // Soft Knee 처리
      const kneeStart = threshold - knee; // knee 폭을 더 넓게 보려면 /2 대신 그대로 사용 가능
      const kneeEnd = threshold + knee;

      if (inputDb < kneeStart) {
        // Knee 구간 아래
        outputDb = inputDb;
      } else if (inputDb > kneeEnd) {
        // Knee 구간 위
        outputDb = threshold + (inputDb - threshold) / ratio;
      } else {
        // Knee 구간 내부 (부드러운 전환)
        // 간단한 보간(smoothstep 등) 사용
        const fraction = (inputDb - kneeStart) / (kneeEnd - kneeStart);
        const before = inputDb; // 압축 전
        const after = threshold + (inputDb - threshold) / ratio; // 압축 후
        // Smoothstep (3t^2 - 2t^3)
        const smooth = fraction * fraction * (3 - 2 * fraction);
        outputDb = before + (after - before) * smooth;
      }
    }

    // 메이크업 게인 적용
    outputDb += gain;

    // Mix (Wet/Dry) 처리
    // Wet = outputDb, Dry = inputDb
    const wet = outputDb;
    const dry = inputDb;
    const mixed = wet * (mix / 100) + dry * (1 - mix / 100);

    // -60 ~ 0 dB 범위로 제한
    return Math.max(-60, Math.min(0, mixed));
  };

  /**
   * 그래프 (SVG)용 데이터 생성
   * - -60dB부터 0dB까지 일정 간격으로 입력값을 스캔하여
   *   compressorTransfer를 통해 출력값을 구함
   */
  const graphWidth = 300;
  const graphHeight = 300;
  const step = 0.5; // 0.5dB 단위로 스캔
  const inputRange = [];

  for (let i = -60; i <= 0; i += step) {
    inputRange.push(i);
  }

  // 폴리라인(Polyline) 좌표 계산
  const points = inputRange.map((x) => {
    const out = compressorTransfer(x);
    const px = ((x + 60) / 60) * graphWidth;   // X 좌표 변환
    const py = graphHeight - ((out + 60) / 60) * graphHeight; // Y 좌표 변환
    return { x: px, y: py, inDb: x, outDb: out };
  });
  const pointsStr = points.map((p) => `${p.x},${p.y}`).join(' ');

  // Knee 지점 등 하이라이트할 포인트 계산
  // (threshold, kneeStart, kneeEnd 등)
  const highlightPoints = [];
  if (knee === 0) {
    // Hard Knee => Threshold 지점 표시
    const outAtThr = threshold + (threshold - threshold) / ratio; // threshold
    // Gain+Mix 등은 이미 compressorTransfer에서 계산됨.
    // 여기서는 스테틱 위치만 표시하기 위해 간단히 표시
    const gx = ((threshold + 60) / 60) * graphWidth;
    const gy = graphHeight - ((outAtThr + gain + 60) / 60) * graphHeight;
    highlightPoints.push({ x: gx, y: gy, label: 'Threshold' });
  } else {
    // Soft Knee => kneeStart, kneeEnd
    const kneeStart = threshold - knee;
    const kneeEnd = threshold + knee;

    // kneeStart
    const outAtStart = compressorTransfer(kneeStart);
    const gx1 = ((kneeStart + 60) / 60) * graphWidth;
    const gy1 = graphHeight - ((outAtStart + 60) / 60) * graphHeight;
    highlightPoints.push({ x: gx1, y: gy1, label: 'Knee Start' });

    // kneeEnd
    const outAtEnd = compressorTransfer(kneeEnd);
    const gx2 = ((kneeEnd + 60) / 60) * graphWidth;
    const gy2 = graphHeight - ((outAtEnd + 60) / 60) * graphHeight;
    highlightPoints.push({ x: gx2, y: gy2, label: 'Knee End' });
  }

  // 파라미터 변경 시 콘솔로 확인 (실제 오디오엔 Web Audio API 등 사용)
  useEffect(() => {
    console.log("Updated parameters =>", {
      attack, hold, release, ratio, threshold, knee, gain, mix
    });
  }, [attack, hold, release, ratio, threshold, knee, gain, mix]);

  return (
    <div className="comp-container">
      {/* 그래프 영역 */}
      <div className="comp-graph-container">
        <h2>Compression Curve</h2>
        <svg width={graphWidth} height={graphHeight} className="comp-graph-svg">
          {/* Transfer Curve 라인 */}
          <polyline
            fill="none"
            stroke="#e74c3c"
            strokeWidth="2"
            points={pointsStr}
          />
          {/* 변화 지점 표시 (Threshold, Knee Start/End) */}
          {highlightPoints.map((pt, i) => (
            <g key={i}>
              <circle
                cx={pt.x}
                cy={pt.y}
                r="4"
                fill="#3498db"
                stroke="#fff"
                strokeWidth="1"
              />
              <text
                x={pt.x + 5}
                y={pt.y - 5}
                fontSize="10"
                fill="#000"
              >
                {pt.label}
              </text>
            </g>
          ))}

          {/* 축 표시 (X,Y) */}
          <line
            x1="0"
            y1={graphHeight}
            x2={graphWidth}
            y2={graphHeight}
            stroke="#888"
            strokeWidth="1"
          />
          <line
            x1="0"
            y1="0"
            x2="0"
            y2={graphHeight}
            stroke="#888"
            strokeWidth="1"
          />
        </svg>
      </div>

      {/* 컨트롤 영역 */}
      <div className="compressor-controls">
        <h2>Compressor Controls</h2>

        <div className="controls">
          {/* Attack */}
          <div
            className="control"
            onMouseEnter={() => setActiveControl("attack")}
            onMouseLeave={() => setActiveControl("")}
          >
            <label>Attack</label>
            <input
              type="range"
              min="0"
              max="120"
              step="1"
              value={attack}
              onChange={(e) => setAttack(Number(e.target.value))}
            />
            <span>{attack} ms</span>
          </div>

          {/* Hold */}
          <div
            className="control"
            onMouseEnter={() => setActiveControl("hold")}
            onMouseLeave={() => setActiveControl("")}
          >
            <label>Hold</label>
            <input
              type="range"
              min="0.02"
              max="2000"
              step="0.01"
              value={hold}
              onChange={(e) => setHold(Number(e.target.value))}
            />
            <span>{hold} ms</span>
          </div>

          {/* Release */}
          <div
            className="control"
            onMouseEnter={() => setActiveControl("release")}
            onMouseLeave={() => setActiveControl("")}
          >
            <label>Release</label>
            <input
              type="range"
              min="5"
              max="4000"
              step="1"
              value={release}
              onChange={(e) => setRelease(Number(e.target.value))}
            />
            <span>{release} ms</span>
          </div>

          {/* Ratio */}
          <div
            className="control"
            onMouseEnter={() => setActiveControl("ratio")}
            onMouseLeave={() => setActiveControl("")}
          >
            <label>Ratio</label>
            <input
              type="range"
              min="1.1"
              max="100"
              step="0.1"
              value={ratio}
              onChange={(e) => setRatio(Number(e.target.value))}
            />
            <span>{ratio.toFixed(1)}:1</span>
          </div>

          {/* Threshold */}
          <div
            className="control"
            onMouseEnter={() => setActiveControl("threshold")}
            onMouseLeave={() => setActiveControl("")}
          >
            <label>Threshold</label>
            <input
              type="range"
              min="-60"
              max="0"
              step="0.5"
              value={threshold}
              onChange={(e) => setThreshold(Number(e.target.value))}
            />
            <span>{threshold.toFixed(1)} dB</span>
          </div>

          {/* Knee */}
          <div
            className="control"
            onMouseEnter={() => setActiveControl("knee")}
            onMouseLeave={() => setActiveControl("")}
          >
            <label>Knee</label>
            <input
              type="range"
              min="0"
              max="5"
              step="0.1"
              value={knee}
              onChange={(e) => setKnee(Number(e.target.value))}
            />
            <span>{knee.toFixed(1)}</span>
          </div>

          {/* Gain */}
          <div
            className="control"
            onMouseEnter={() => setActiveControl("gain")}
            onMouseLeave={() => setActiveControl("")}
          >
            <label>Gain</label>
            <input
              type="range"
              min="0"
              max="24"
              step="0.1"
              value={gain}
              onChange={(e) => setGain(Number(e.target.value))}
            />
            <span>{gain.toFixed(1)} dB</span>
          </div>

          {/* Mix */}
          <div
            className="control"
            onMouseEnter={() => setActiveControl("mix")}
            onMouseLeave={() => setActiveControl("")}
          >
            <label>Mix</label>
            <input
              type="range"
              min="0"
              max="100"
              step="1"
              value={mix}
              onChange={(e) => setMix(Number(e.target.value))}
            />
            <span>{mix}%</span>
          </div>
        </div>

        {/* Hover 설명 (항상 컨테이너는 존재, 텍스트만 바뀜) */}
        <div className="description-container">
          {activeControl ? (
            <p className="description-text">
              {controlDescriptions[activeControl]}
            </p>
          ) : (
            <p className="description-text">
              마우스를 올려놓으면 해당 파라미터의 상세 설명이 표시됩니다.
            </p>
          )}
        </div>
      </div>
    </div>
  );
};

export default Comp;
