import React, { useState, useEffect, useRef } from 'react';
import '../../Styles/reverbtwo.css';

/** dB -> Gain 변환 함수 */
function dbToGain(db) {
  return Math.pow(10, db / 20);
}

/** Freeverb 스타일 알고리즘 리버브 (Comb + Allpass)
 * (UI/그래프 시뮬레이션용 DSP 예시)
 */
function createAlgorithmicReverb(audioCtx, mixValue) {
  const validMix = isFinite(mixValue) ? mixValue : 50;
  const input = audioCtx.createGain();
  const output = audioCtx.createGain();

  // Comb 필터들
  const combDelays = [0.0297, 0.0371, 0.0411, 0.0437];
  const combFilters = combDelays.map(dt => {
    const delay = audioCtx.createDelay();
    delay.delayTime.value = dt;
    const feedback = audioCtx.createGain();
    feedback.gain.value = 0.8;
    delay.connect(feedback);
    feedback.connect(delay);
    return delay;
  });
  combFilters.forEach(cf => input.connect(cf));
  const combSum = audioCtx.createGain();
  combSum.gain.value = 1 / combFilters.length;
  combFilters.forEach(cf => cf.connect(combSum));

  // Allpass 필터
  const allpassDelays = [0.005, 0.0017];
  let allpass = combSum;
  allpassDelays.forEach(dt => {
    const apDelay = audioCtx.createDelay();
    apDelay.delayTime.value = dt;
    const apGain = audioCtx.createGain();
    apGain.gain.value = 0.7;
    allpass.connect(apDelay);
    apDelay.connect(apGain);
    apGain.connect(apDelay);
    allpass = apDelay;
  });

  // Wet/Dry 믹싱
  const wetGain = audioCtx.createGain();
  wetGain.gain.value = validMix / 100;
  const dryGain = audioCtx.createGain();
  dryGain.gain.value = 1 - validMix / 100;

  input.connect(dryGain);
  allpass.connect(wetGain);

  const merger = audioCtx.createGain();
  dryGain.connect(merger);
  wetGain.connect(merger);
  merger.connect(output);

  return { input, output, wetGain, dryGain };
}

/** 수정된 파라메트릭 EQ 커브 계산 함수
 * center와 q가 독립적으로 작용: sigma를 고정 상수(예, 1000) 기반으로 계산
 */
function getPeakingEQGainFixed(f, center, q, gain) {
  const sigma = 1000 / q; // 고정 상수 1000을 사용
  return gain * Math.exp(-0.5 * Math.pow((f - center) / sigma, 2));
}

/** Damping 곡선 계산 함수 (Gaussian 모형, 고정 sigma)
 * center: 중심 주파수, ratio: 최대 시간(ms) 값, 
 * Q는 여기서는 고정(예, 1.0)로 사용하여 폭 조절 효과만 반영
 */
function getDampingValue(f, center, ratio) {
  const sigma = 1000; // 폭 조절 상수 (필요 시 조절)
  return ratio * Math.exp(-0.5 * Math.pow((f - center) / sigma, 2));
}

/** 슬라이더(페이더) UI 컴포넌트 */
const Fader = ({ label, value, min, max, step, onChange }) => (
  <div className="eqtwo-fader-control">
    <div className="eqtwo-fader-label">{label}</div>
    <input
      type="range"
      className="eqtwo-fader-input"
      value={value}
      min={min}
      max={max}
      step={step}
      onChange={e => onChange(parseFloat(e.target.value))}
    />
    <div className="eqtwo-fader-value">{value}</div>
  </div>
);

/** MongoDB에 리버브 설정 저장 (API 호출 예시) */
async function saveReverbSettings(settings) {
  try {
    await fetch('/api/reverb-settings', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(settings)
    });
  } catch (error) {
    console.error('Failed to save reverb settings:', error);
  }
}

/** Catmull-Rom 스플라인 보간 함수 */
function catmullRom(t, p0, p1, p2, p3) {
  const t2 = t * t;
  const t3 = t2 * t;
  return 0.5 * ((2 * p1) + (-p0 + p2) * t + (2 * p0 - 5 * p1 + 4 * p2 - p3) * t2 + (-p0 + 3 * p1 - 3 * p2 + p3) * t3);
}

/** Time Response X축 레이블 렌더링 함수 */
function renderTimeAxis(timeGraphData) {
  const labels = [];
  const maxMs = timeGraphData[timeGraphData.length - 1] || 1000;
  const step = maxMs / 10;
  for (let i = 0; i <= 10; i++) {
    labels.push(
      <div key={i} className="eqtwo-hz-label">
        {Math.floor(i * step)} ms
      </div>
    );
  }
  return <div className="eqtwo-time-axis">{labels}</div>;
}

/* ------------------- Reverbtwo 컴포넌트 ------------------- */
const Reverbtwo = () => {
  // 상단 컨트롤 상태
  const [roomType, setRoomType] = useState('room');
  const [audioSourceType, setAudioSourceType] = useState('file');
  const [audioFile, setAudioFile] = useState(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [playbackOffset, setPlaybackOffset] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [volume, setVolume] = useState(-20);
  const [fileDuration, setFileDuration] = useState(0);

  // EQ 파라미터 (4채널)
  const [eqParams, setEqParams] = useState({
    low: { freq: 80, q: 0.7, gain: 0, mode: 'shelf' },
    lowMid: { freq: 400, q: 1.0, gain: 0 },
    highMid: { freq: 2000, q: 1.0, gain: 0 },
    high: { freq: 8000, q: 0.7, gain: 0, mode: 'shelf' }
  });
  const [selectedChannel, setSelectedChannel] = useState("low");

  // Damping 파라미터: Low, Mid, High (ratio는 ms 단위의 최대 차이를 의미)
  const [dampLowFreq, setDampLowFreq] = useState(200);
  const [dampLowRatio, setDampLowRatio] = useState(100);
  const [dampMidFreq, setDampMidFreq] = useState(1000);
  const [dampMidRatio, setDampMidRatio] = useState(100);
  const [dampHighFreq, setDampHighFreq] = useState(8000);
  const [dampHighRatio, setDampHighRatio] = useState(100);

  // Time Response 파라미터
  const [preDelay, setPreDelay] = useState(30); // ms
  const [timeValue, setTimeValue] = useState(1.0); // s
  const [size, setSize] = useState(50);
  const [diffusion, setDiffusion] = useState(50);
  const [decay, setDecay] = useState(2.0);

  // Basic 파라미터
  const [mix, setMix] = useState(50);
  const [wet, setWet] = useState(50);
  const [dry, setDry] = useState(50);
  const [stereoWidth, setStereoWidth] = useState(50);
  const [attack, setAttack] = useState(10);

  // 그래프 데이터
  const [eqGraphData, setEqGraphData] = useState([]);
  const [dampingGraphData, setDampingGraphData] = useState([]);
  const [timeGraphData, setTimeGraphData] = useState([]);

  // AudioContext 및 DSP 관련 refs
  const audioContextRef = useRef(null);
  const reverbNodeRef = useRef(null);
  const preDelayNodeRef = useRef(null);
  const gainNodeRef = useRef(null);
  const analyserRef = useRef(null);
  const fileAudioBufferRef = useRef(null);
  const fileSourceRef = useRef(null);
  const playbackStartTimeRef = useRef(0);
  const timelineIntervalRef = useRef(null);

  // Canvas refs for 그래프
  const eqCanvasRef = useRef(null);
  const dampingCanvasRef = useRef(null);
  const timeCanvasRef = useRef(null);

  // Room 타입에 따른 기본 파라미터 적용
  useEffect(() => {
    switch (roomType) {
      case 'room':
        setDecay(2.0);
        setSize(40);
        setTimeValue(1.0);
        break;
      case 'hall':
        setDecay(4.0);
        setSize(80);
        setTimeValue(2.0);
        break;
      case 'plate':
        setDecay(3.5);
        setSize(60);
        setTimeValue(1.5);
        break;
      case 'chamber':
        setDecay(4.5);
        setSize(70);
        setTimeValue(2.5);
        break;
      default:
        break;
    }
  }, [roomType]);

  // MongoDB에 리버브 설정 저장
  useEffect(() => {
    const settings = {
      roomType,
      eqParams,
      damping: { dampLowFreq, dampLowRatio, dampMidFreq, dampMidRatio, dampHighFreq, dampHighRatio },
      timeResponse: { preDelay, timeValue, size, diffusion, decay },
      basic: { mix, wet, dry, stereoWidth, attack }
    };
    saveReverbSettings(settings);
  }, [roomType, eqParams, dampLowFreq, dampLowRatio, dampMidFreq, dampMidRatio, dampHighFreq, dampHighRatio, preDelay, timeValue, size, diffusion, decay, mix, wet, dry, stereoWidth, attack]);

  // AudioContext 및 DSP 초기화
  const setupAudio = async () => {
    if (audioContextRef.current) {
      try {
        await audioContextRef.current.close();
      } catch (e) {
        console.error(e);
      }
    }
    audioContextRef.current = null;
    reverbNodeRef.current = null;
    preDelayNodeRef.current = null;
    gainNodeRef.current = null;
    analyserRef.current = null;

    const AudioContext = window.AudioContext || window.webkitAudioContext;
    const audioCtx = new AudioContext();
    audioContextRef.current = audioCtx;

    // Gain
    gainNodeRef.current = audioCtx.createGain();
    gainNodeRef.current.gain.value = dbToGain(volume);

    // PreDelay
    preDelayNodeRef.current = audioCtx.createDelay();
    preDelayNodeRef.current.delayTime.value = isFinite(preDelay) ? preDelay / 1000 : 0.03;

    // 리버브
    reverbNodeRef.current = createAlgorithmicReverb(audioCtx, mix);

    // Analyser
    analyserRef.current = audioCtx.createAnalyser();
    analyserRef.current.fftSize = 2048;

    // DSP 체인: source -> PreDelay -> 리버브 -> Gain -> Analyser -> Destination
    preDelayNodeRef.current.connect(reverbNodeRef.current.input);
    reverbNodeRef.current.output.connect(gainNodeRef.current);
    gainNodeRef.current.connect(analyserRef.current);
    analyserRef.current.connect(audioCtx.destination);

    // 오디오 소스 처리
    if (audioSourceType === 'mic') {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        const source = audioCtx.createMediaStreamSource(stream);
        source.connect(preDelayNodeRef.current);
      } catch (err) {
        console.error('Mic error:', err);
      }
    } else if (audioSourceType === 'file' && audioFile) {
      const reader = new FileReader();
      reader.onload = async (e) => {
        try {
          const audioBuffer = await audioCtx.decodeAudioData(e.target.result);
          fileAudioBufferRef.current = audioBuffer;
          setFileDuration(audioBuffer.duration);
        } catch (error) {
          console.error('Decode error:', error);
        }
      };
      reader.readAsArrayBuffer(audioFile);
    }
  };

  useEffect(() => {
    setupAudio();
    return () => {
      if (timelineIntervalRef.current) clearInterval(timelineIntervalRef.current);
      if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
        audioContextRef.current.close();
      }
    };
  }, [audioSourceType, audioFile, roomType]);

  /** 재생/정지/스킵/타임라인 컨트롤 */
  const playFile = async () => {
    if (!fileAudioBufferRef.current || !audioContextRef.current) return;
    if (isPlaying) return;
    const audioCtx = audioContextRef.current;
    await audioCtx.resume();
    const source = audioCtx.createBufferSource();
    source.buffer = fileAudioBufferRef.current;
    source.loop = true;
    source.connect(preDelayNodeRef.current);
    fileSourceRef.current = source;
    playbackStartTimeRef.current = audioCtx.currentTime - playbackOffset;
    source.start(0, playbackOffset);
    setIsPlaying(true);
    timelineIntervalRef.current = setInterval(() => {
      const newTime = audioCtx.currentTime - playbackStartTimeRef.current;
      setCurrentTime(newTime);
    }, 200);
  };

  const pauseFile = () => {
    if (!isPlaying || !fileSourceRef.current) return;
    const audioCtx = audioContextRef.current;
    const elapsed = audioCtx.currentTime - playbackStartTimeRef.current;
    setPlaybackOffset(playbackOffset + elapsed);
    try {
      fileSourceRef.current.stop();
    } catch (e) {
      console.error(e);
    }
    setIsPlaying(false);
    if (timelineIntervalRef.current) clearInterval(timelineIntervalRef.current);
  };

  const skipForward = () => {
    const newOffset = playbackOffset + 5;
    if (isPlaying) {
      pauseFile();
      setPlaybackOffset(newOffset);
      setTimeout(playFile, 0);
    } else {
      setPlaybackOffset(newOffset);
    }
  };

  const skipBackward = () => {
    const newOffset = Math.max(0, playbackOffset - 5);
    if (isPlaying) {
      pauseFile();
      setPlaybackOffset(newOffset);
      setTimeout(playFile, 0);
    } else {
      setPlaybackOffset(newOffset);
    }
  };

  const handleVolumeChange = (e) => {
    const newDb = parseFloat(e.target.value);
    setVolume(newDb);
    if (gainNodeRef.current) {
      gainNodeRef.current.gain.value = dbToGain(newDb);
    }
  };

  const handleSourceChange = (e) => {
    setAudioSourceType(e.target.value);
  };

  const handleFileChangeForSource = (e) => {
    if (e.target.files.length > 0) {
      setAudioFile(e.target.files[0]);
    }
  };

  /** 그래프 데이터 업데이트 */
  useEffect(() => {
    // EQ 그래프 데이터 업데이트 (파라메트릭 EQ: Freq만 이동, Q는 폭)
    if (analyserRef.current) {
      const bufferLength = analyserRef.current.frequencyBinCount;
      const dataArray = new Uint8Array(bufferLength);
      analyserRef.current.getByteFrequencyData(dataArray);
      const numPoints = 2001;
      const eqArr = [];
      for (let i = 0; i < numPoints; i++) {
        const f = 20 + (i / (numPoints - 1)) * (20000 - 20);
        const bin = Math.floor((f / (44100 / 2)) * bufferLength);
        const value = dataArray[bin] || 0;
        const inputDb = (value / 255) * 15 - 15;
        // getPeakingEQGainFixed 사용: Freq 조절 시 중심만 이동, Q는 폭만 결정
        const eqLow = getPeakingEQGainFixed(f, eqParams.low.freq, eqParams.low.q, eqParams.low.gain);
        const eqLowMid = getPeakingEQGainFixed(f, eqParams.lowMid.freq, eqParams.lowMid.q, eqParams.lowMid.gain);
        const eqHighMid = getPeakingEQGainFixed(f, eqParams.highMid.freq, eqParams.highMid.q, eqParams.highMid.gain);
        const eqHigh = getPeakingEQGainFixed(f, eqParams.high.freq, eqParams.high.q, eqParams.high.gain);
        let eqDb = eqLow + eqLowMid + eqHighMid + eqHigh;
        eqDb = Math.min(Math.max(eqDb, -15), 15);
        eqArr.push({ hz: f, inputDb, eqDb });
      }
      setEqGraphData(eqArr);
    }

    // Damping 그래프 데이터 업데이트: 각 밴드의 Gaussian 곡선을 합산 (파라메트릭 EQ 스타일)
    const numPoints = 2001;
    const dampArr = [];
    for (let i = 0; i < numPoints; i++) {
      const f = 20 + (i / (numPoints - 1)) * (20000 - 20);
      // 각 밴드의 damping 값 계산 (단, damping 값은 ms 단위)
      const dLow = getDampingValue(f, dampLowFreq, dampLowRatio);
      const dMid = getDampingValue(f, dampMidFreq, dampMidRatio);
      const dHigh = getDampingValue(f, dampHighFreq, dampHighRatio);
      // 전체 damping 값: 평균값으로 계산
      const dampingValue = (dLow + dMid + dHigh) / 3;
      // normalize y: assume max damping is, e.g., 200 ms for drawing (여기서는 200ms를 최댓값)
      dampArr.push({ x: ( (f-20) / (20000-20) ) * 500, y: 250 - (dampingValue / 200) * 250 });
    }
    setDampingGraphData(dampArr);

    // Time Response 그래프 데이터 업데이트: x축 ms, 간격 50ms, 최대 시간 = timeValue*1000 + preDelay + 500
    const maxMs = Math.floor(timeValue * 1000 + preDelay + 500);
    const tArr = [];
    for (let ms = 0; ms <= maxMs; ms += 50) {
      tArr.push(ms);
    }
    setTimeGraphData(tArr);
  }, [eqParams, dampLowFreq, dampLowRatio, dampMidFreq, dampMidRatio, dampHighFreq, dampHighRatio, preDelay, timeValue, diffusion, decay]);

  /** 그래프 그리기 함수: EQ, Damping, Time Response */
  function drawEqGraph(ctx, w, h) {
    ctx.clearRect(0, 0, w, h);
    ctx.fillStyle = '#000';
    ctx.fillRect(0, 0, w, h);
    if (eqGraphData.length === 0) return;
    const stepX = w / eqGraphData.length;
    // 중심선 (0 dB)
    ctx.strokeStyle = 'rgba(255,255,255,0.3)';
    ctx.setLineDash([5, 5]);
    ctx.beginPath();
    ctx.moveTo(0, h / 2);
    ctx.lineTo(w, h / 2);
    ctx.stroke();
    ctx.setLineDash([]);
    // 빨간 막대: 입력 주파수 신호
    eqGraphData.forEach((d, i) => {
      const x = i * stepX;
      const ratio = (d.inputDb + 15) / 15;
      const barHeight = ratio * (h / 2);
      ctx.fillStyle = 'red';
      ctx.fillRect(x, h / 2 - barHeight, stepX, barHeight);
    });
    // 파라메트릭 EQ 커브
    ctx.beginPath();
    eqGraphData.forEach((d, i) => {
      const x = i * stepX;
      const eqRatio = (d.eqDb + 15) / 30;
      const y = h - eqRatio * h;
      if (i === 0) ctx.moveTo(x, y);
      else ctx.lineTo(x, y);
    });
    ctx.strokeStyle = 'cyan';
    ctx.lineWidth = 1.5;
    ctx.stroke();
    // 중심 0 dB 라벨
    ctx.fillStyle = '#ccc';
    ctx.font = '12px Arial';
    ctx.fillText('Param EQ (-15dB ~ +15dB)', 10, 15);
  }

  function drawDampingGraph(ctx, w, h) {
    ctx.clearRect(0, 0, w, h);
    ctx.fillStyle = '#000';
    ctx.fillRect(0, 0, w, h);
    if (dampingGraphData.length === 0) return;
    // 중심선 (100% damping = 100% 기준)
    ctx.strokeStyle = 'rgba(255,255,255,0.3)';
    ctx.setLineDash([5, 5]);
    ctx.beginPath();
    ctx.moveTo(0, h - (250 / 250) * h); // 100% damping 위치, 여기서는 250px에서 계산
    ctx.lineTo(w, h - (250 / 250) * h);
    ctx.stroke();
    ctx.setLineDash([]);
    // Damping 곡선
    ctx.beginPath();
    dampingGraphData.forEach((point, i) => {
      if (i === 0) ctx.moveTo(point.x, point.y);
      else ctx.lineTo(point.x, point.y);
    });
    ctx.strokeStyle = '#ff5722';
    ctx.lineWidth = 2;
    ctx.stroke();
    ctx.fillStyle = '#ccc';
    ctx.font = '12px Arial';
    ctx.fillText('Damping (0% ~ 200%), 0~20kHz', 10, 15);
  }

  function drawTimeGraph(ctx, w, h) {
    ctx.clearRect(0, 0, w, h);
    ctx.fillStyle = '#000';
    ctx.fillRect(0, 0, w, h);
    // Time Response: 실시간 스펙트럼 (오른쪽 그래프)
    // 캔버스 전체를 좌측으로 1px 이동
    const imageData = ctx.getImageData(1, 0, w - 1, h);
    ctx.putImageData(imageData, 0, 0);
    const bufferLength = analyserRef.current.frequencyBinCount;
    const freqData = new Uint8Array(bufferLength);
    analyserRef.current.getByteFrequencyData(freqData);
    // 새 데이터: 각 y 픽셀에 대해 신호 세기를 옅은 초록에서 빨강 그라데이션으로 표시
    for (let y = 0; y < h; y++) {
      // y: 0 (상단, +0dB) ~ h (하단, -15dB)
      // 여기서는 단순히 전체 평균 값을 사용
      const avg = freqData.reduce((sum, val) => sum + val, 0) / bufferLength;
      const intensity = avg / 255;
      const r = Math.round(255 * intensity);
      const g = Math.round(255 * (1 - intensity));
      ctx.fillStyle = `rgb(${r}, ${g}, 0)`;
      ctx.fillRect(w - 1, y, 1, 1);
    }
  }

  useEffect(() => {
    let animId;
    const loop = () => {
      if (eqCanvasRef.current) {
        const ctx = eqCanvasRef.current.getContext('2d');
        drawEqGraph(ctx, eqCanvasRef.current.width, eqCanvasRef.current.height);
      }
      if (dampingCanvasRef.current) {
        const ctx = dampingCanvasRef.current.getContext('2d');
        drawDampingGraph(ctx, dampingCanvasRef.current.width, dampingCanvasRef.current.height);
      }
      if (timeCanvasRef.current) {
        const ctx = timeCanvasRef.current.getContext('2d');
        drawTimeGraph(ctx, timeCanvasRef.current.width, timeCanvasRef.current.height);
      }
      animId = requestAnimationFrame(loop);
    };
    loop();
    return () => cancelAnimationFrame(animId);
  }, [eqGraphData, dampingGraphData, timeGraphData, preDelay, decay]);

  /** EQ 채널 선택 및 파라미터 조절 UI */
  const handleEqChannelChange = (channel) => {
    setSelectedChannel(channel);
  };

  const updateEqParam = (channel, key, value) => {
    setEqParams(prev => ({
      ...prev,
      [channel]: {
        ...prev[channel],
        [key]: value
      }
    }));
  };

  return (
    <div className="eqtwo-full-container">
      {/* 상단 컨트롤 영역 */}
      <header className="eqtwo-header">
        <div className="eqtwo-playback-controls">
          <button onClick={playFile} disabled={isPlaying || !fileAudioBufferRef.current}>Play</button>
          <button onClick={pauseFile} disabled={!isPlaying}>Pause</button>
          <button onClick={skipBackward} disabled={!fileAudioBufferRef.current}>-5s</button>
          <button onClick={skipForward} disabled={!fileAudioBufferRef.current}>+5s</button>
          <input
            type="range"
            className="eqtwo-timeline-slider"
            min="0"
            max={fileDuration}
            step="0.1"
            value={currentTime}
            onChange={(e) => {
              const newTime = parseFloat(e.target.value);
              setCurrentTime(newTime);
              if (isPlaying) {
                pauseFile();
                setPlaybackOffset(newTime);
                setTimeout(playFile, 0);
              } else {
                setPlaybackOffset(newTime);
              }
            }}
          />
          <span className="eqtwo-time-display">{currentTime.toFixed(1)}/{fileDuration.toFixed(1)}s</span>
        </div>
        <div className="eqtwo-source-controls">
          <label>Audio Source:</label>
          <select value={audioSourceType} onChange={handleSourceChange}>
            <option value="mic">Mic</option>
            <option value="file">File</option>
            <option value="usb">USB</option>
          </select>
          {audioSourceType === 'file' && (
            <input type="file" accept="audio/*" onChange={handleFileChangeForSource} />
          )}
        </div>
        <div className="eqtwo-room-controls">
          <label>Room:</label>
          <select value={roomType} onChange={e => setRoomType(e.target.value)}>
            <option value="room">Room</option>
            <option value="plate">Plate</option>
            <option value="hall">Hall</option>
            <option value="chamber">Chamber</option>
          </select>
          <div className="eqtwo-volume-control">
            <label>Vol(dB):</label>
            <input
              type="range"
              min="-90"
              max="10"
              step="0.1"
              value={volume}
              onChange={handleVolumeChange}
            />
            <span>{volume} dB</span>
          </div>
        </div>
      </header>

      {/* 중앙 그래프 영역: 좌측 EQ & Damping (세로 정렬), 우측 Time Response */}
      <div className="eqtwo-graphs-container">
        <div className="eqtwo-left-graphs">
          <canvas ref={eqCanvasRef} className="eqtwo-graph-canvas eqtwo-eq-canvas" width="500" height="250" />
          <canvas ref={dampingCanvasRef} className="eqtwo-graph-canvas eqtwo-damping-canvas" width="500" height="250" />
        </div>
        <div className="eqtwo-right-graph">
          <canvas ref={timeCanvasRef} className="eqtwo-graph-canvas eqtwo-time-canvas" width="600" height="500" />
          {renderTimeAxis(timeGraphData)}
        </div>
      </div>

      {/* 하단 Faders 섹션 (EQ, Damping, Time, Basic 컨트롤 통합) */}
      <div className="eqtwo-faders-section">
        <div className="eqtwo-eq-controls">
          <h4>EQ Channel Selection &amp; Controls</h4>
          <select value={selectedChannel} onChange={e => handleEqChannelChange(e.target.value)}>
            <option value="low">Low</option>
            <option value="lowMid">Low-mid</option>
            <option value="highMid">High-mid</option>
            <option value="high">High</option>
          </select>
          <div className="eqtwo-eq-channel-controls">
            <Fader label="Freq" value={eqParams[selectedChannel].freq} min={20} max={20000} step={10} onChange={(val) => updateEqParam(selectedChannel, 'freq', val)} />
            <Fader label="Q" value={eqParams[selectedChannel].q} min={0.1} max={10} step={0.1} onChange={(val) => updateEqParam(selectedChannel, 'q', val)} />
            <Fader label="Gain" value={eqParams[selectedChannel].gain} min={-15} max={15} step={0.5} onChange={(val) => updateEqParam(selectedChannel, 'gain', val)} />
            {(selectedChannel === 'low' || selectedChannel === 'high') && (
              <div className="eqtwo-fader-control">
                <div className="eqtwo-fader-label">Mode</div>
                <select value={eqParams[selectedChannel].mode} onChange={e => updateEqParam(selectedChannel, 'mode', e.target.value)}>
                  <option value="shelf">Shelf</option>
                  <option value="cut">Cut</option>
                </select>
              </div>
            )}
          </div>
        </div>

        <div className="eqtwo-fader-group eqtwo-damping-group">
          <h4>Damping Controls</h4>
          <Fader label="Low-Freq" value={dampLowFreq} min={20} max={20000} step={10} onChange={setDampLowFreq} />
          <Fader label="Low-Ratio(%)" value={dampLowRatio} min={0} max={200} step={1} onChange={setDampLowRatio} />
          <Fader label="Mid-Freq" value={dampMidFreq} min={20} max={20000} step={10} onChange={setDampMidFreq} />
          <Fader label="Mid-Ratio(%)" value={dampMidRatio} min={0} max={200} step={1} onChange={setDampMidRatio} />
          <Fader label="High-Freq" value={dampHighFreq} min={20} max={20000} step={10} onChange={setDampHighFreq} />
          <Fader label="High-Ratio(%)" value={dampHighRatio} min={0} max={200} step={1} onChange={setDampHighRatio} />
        </div>

        <div className="eqtwo-fader-group eqtwo-time-group">
          <h4>Time Response Controls</h4>
          <Fader label="PreDelay(ms)" value={preDelay} min={0} max={150} step={1} onChange={setPreDelay} />
          <Fader label="Time(s)" value={timeValue} min={0.1} max={20} step={0.1} onChange={setTimeValue} />
          <Fader label="Size(%)" value={size} min={0} max={100} step={1} onChange={setSize} />
          <Fader label="Diffusion(%)" value={diffusion} min={0} max={100} step={1} onChange={setDiffusion} />
          <Fader label="Decay" value={decay} min={0.1} max={5} step={0.1} onChange={setDecay} />
        </div>

        <div className="eqtwo-fader-group eqtwo-basic-group">
          <h4>Basic Controls</h4>
          <Fader label="Mix(%)" value={mix} min={0} max={100} step={1} onChange={setMix} />
          <Fader label="Wet(%)" value={wet} min={0} max={100} step={1} onChange={setWet} />
          <Fader label="Dry(%)" value={dry} min={0} max={100} step={1} onChange={setDry} />
          <Fader label="StereoWidth(%)" value={stereoWidth} min={0} max={100} step={1} onChange={setStereoWidth} />
          <Fader label="Attack(%)" value={attack} min={0} max={100} step={1} onChange={setAttack} />
        </div>
      </div>
    </div>
  );
};

export default Reverbtwo;
